import (
	"strconv"
	"strings"
)

func solve(n int64) string {
	nSquared := n * n
	hexPart := strings.ToUpper(strconv.FormatInt(nSquared, 16))

	nCubed := n * n * n
	var base36Part string
	if nCubed == 0 {
		base36Part = "0"
	} else {
		var digits []string
		num := nCubed
		for num > 0 {
			remainder := num % 36
			if remainder < 10 {
				digits = append(digits, strconv.FormatInt(remainder, 10))
			} else {
				digits = append(digits, string('A'+remainder-10))
			}
			num = num / 36
		}
		// Reverse the digits
		for i, j := 0, len(digits)-1; i < j; i, j = i+1, j-1 {
			digits[i], digits[j] = digits[j], digits[i]
		}
		base36Part = strings.Join(digits, "")
	}
	return hexPart + base36Part
}
